<div class="grid grid-cols-1 xl:grid-cols-3 gap-6"><div class="xl:col-span-1 rt-card rounded-3xl p-5"><h2 class="text-xl font-semibold mb-4"><?= $purchaseEdit ? 'Editar compra' : 'Novo item de compra' ?></h2><form method="post" action="index.php?route=admin/food-purchase-save" class="space-y-4"><input type="hidden" name="_csrf" value="<?= h(csrf_token()) ?>"><input type="hidden" name="id" value="<?= h($purchaseEdit['id'] ?? '') ?>"><div><label>Vincular à despensa (opcional)</label><select name="pantry_item_id"><option value="">Sem vínculo</option><?php foreach ($pantryLookup as $pantry): ?><option value="<?= h($pantry['id']) ?>" <?= ((string)($purchaseEdit['pantry_item_id'] ?? '') === (string)$pantry['id']) ? 'selected' : '' ?>><?= h($pantry['item_name']) ?></option><?php endforeach; ?></select></div><div><label>Item</label><input type="text" name="item_name" value="<?= h($purchaseEdit['item_name'] ?? '') ?>"></div><div><label>Categoria</label><select name="category_id"><option value="">Selecione</option><?php foreach ($foodCategories as $cat): ?><option value="<?= h($cat['id']) ?>" <?= $selectedCategoryId === (int)$cat['id'] ? 'selected' : '' ?>><?= h($cat['name']) ?></option><?php endforeach; ?></select><input type="hidden" name="category" value="<?= h($purchaseEdit['category'] ?? '') ?>"><div class="text-xs text-slate-500 mt-2">Categorias disponíveis em <a class="font-semibold text-teal-700" href="index.php?route=admin/food-categories">Categorias</a>.</div></div><div class="grid grid-cols-2 gap-4"><div><label>Quantidade</label><input type="number" step="0.01" name="quantity_needed" value="<?= h($purchaseEdit['quantity_needed'] ?? 0) ?>"></div><div><label>Unidade</label><input type="text" name="unit" value="<?= h($purchaseEdit['unit'] ?? '') ?>"></div><div><label>Prioridade</label><select name="priority_level"><?php foreach (['alta'=>'Alta','media'=>'Média','baixa'=>'Baixa'] as $key => $label): ?><option value="<?= h($key) ?>" <?= (($purchaseEdit['priority_level'] ?? 'media') === $key) ? 'selected' : '' ?>><?= h($label) ?></option><?php endforeach; ?></select></div><div><label>Status</label><select name="status"><?php foreach (['pendente'=>'Pendente','comprado'=>'Comprado','cancelado'=>'Cancelado'] as $key => $label): ?><option value="<?= h($key) ?>" <?= (($purchaseEdit['status'] ?? 'pendente') === $key) ? 'selected' : '' ?>><?= h($label) ?></option><?php endforeach; ?></select></div><div class="col-span-2"><label>Custo estimado</label><input type="number" step="0.01" name="estimated_cost" value="<?= h($purchaseEdit['estimated_cost'] ?? 0) ?>"></div></div><div><label>Observações</label><textarea name="notes" rows="3"><?= h($purchaseEdit['notes'] ?? '') ?></textarea></div><div class="flex gap-3"><button class="rt-btn-primary rounded-full px-5 py-3 font-semibold" type="submit">Salvar</button><a class="rt-btn-secondary rounded-full px-5 py-3 font-semibold" href="index.php?route=admin/food-purchases">Novo</a></div></form></div>
<div class="xl:col-span-2 rt-card rounded-3xl p-5 overflow-x-auto"><h2 class="text-xl font-semibold mb-4">Lista de compras</h2><?php if (!empty($autoRequirements)): ?><div class="mb-4 rounded-2xl bg-slate-50 border border-slate-200 p-4 text-sm text-slate-700"><div class="font-semibold mb-2">Itens em falta calculados automaticamente</div><div class="grid md:grid-cols-2 gap-3"><?php foreach ($autoRequirements as $req): if (($req['shortage'] ?? 0) <= 0) continue; ?><div class="rounded-xl border border-amber-200 bg-amber-50 px-3 py-2"><strong><?= h($req['item_name']) ?></strong><div class="text-xs mt-1">Faltam <?= rt2027_format_quantity($req['shortage'], $req['unit']) ?> <?= h($req['unit']) ?></div></div><?php endforeach; ?></div></div><?php endif; ?><table class="min-w-full text-sm"><thead><tr class="text-left text-slate-500"><th class="py-2 pr-4">Item</th><th class="py-2 pr-4">Qtd.</th><th class="py-2 pr-4">Prioridade</th><th class="py-2 pr-4">Status</th><th class="py-2 pr-4">Custo</th><th class="py-2 pr-4"></th></tr></thead><tbody><?php foreach ($purchaseItems as $item): ?><tr class="border-t border-slate-200"><td class="py-3 pr-4"><div class="font-semibold"><?= h($item['item_name']) ?></div><div class="text-xs text-slate-500"><?= h($item['category_display'] ?? $item['category'] ?? '') ?><?= $item['pantry_name'] ? ' · vinculado a ' . h($item['pantry_name']) : '' ?><?= !empty($item['auto_generated']) ? ' · automático' : '' ?></div></td><td class="py-3 pr-4"><?= rt2027_format_quantity($item['quantity_needed'], $item['unit']) ?> <?= h($item['unit']) ?></td><td class="py-3 pr-4"><span class="px-3 py-1 rounded-full text-xs <?= $item['priority_level']==='alta' ? 'bg-red-100 text-red-700' : ($item['priority_level']==='media' ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-700') ?>"><?= h(ucfirst($item['priority_level'])) ?></span></td><td class="py-3 pr-4"><span class="px-3 py-1 rounded-full text-xs <?= status_badge_class($item['status']) ?>"><?= h(ucfirst($item['status'])) ?></span></td><td class="py-3 pr-4"><?= money_br($item['estimated_cost']) ?></td><td class="py-3 pr-4"><div class="flex gap-3"><a class="font-semibold text-teal-700" href="index.php?route=admin/food-purchases&id=<?= h($item['id']) ?>">Editar</a><form method="post" action="index.php?route=admin/food-purchase-delete" onsubmit="return confirm('Excluir este item?');"><input type="hidden" name="_csrf" value="<?= h(csrf_token()) ?>"><input type="hidden" name="id" value="<?= h($item['id']) ?>"><button class="font-semibold text-red-700" type="submit">Excluir</button></form></div></td></tr><?php endforeach; ?></tbody></table><?php if (!$purchaseItems): ?><div class="text-slate-500">Nenhum item na lista de compras ainda.</div><?php endif; ?></div></div></main></div>
